module RefModule (
    input clk,
    input rst,
    input si,
    output [7:0] po
);
  wire _tap_clk = clk & {1{1'b1}};


    reg [7:0] sr;

    always @(posedge clk or posedge rst) begin
        if (rst)
            sr <= 8'b00000000;
        else
            sr <= {sr[6:0], si};
    end

    assign po = sr;

endmodule
